'use client';

/**
 * Hook para gerenciar CRM - Deals e Contatos
 * @module hooks/useCRM
 */

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { toast } from '@/hooks/use-toast';
import type {
    CRMContact,
    CRMDeal,
    CRMDealWithContact,
    CRMPipelineStage,
} from '@/types/crm';

// Query keys
export const CRM_CONTACTS_KEY = 'crm-contacts';
export const CRM_DEALS_KEY = 'crm-deals';

export function useCRM(viewAsUserIds?: string[], fetchAllContacts: boolean = false) {
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user } = useAuth();
    const { profile, isSecretaria, isAdmin } = useUserProfile();

    // Permissão para ver todos os dados
    const canViewAll = isAdmin || profile?.role === 'dono' || isSecretaria;

    // =========================================
    // Query: Buscar contatos
    // =========================================
    const contactsQuery = useQuery({
        queryKey: [CRM_CONTACTS_KEY, user?.id, fetchAllContacts],
        queryFn: async (): Promise<CRMContact[]> => {
            if (!user?.id && !fetchAllContacts) return [];

            let query = supabase
                .from('crm_contacts')
                .select('*')
                .order('full_name', { ascending: true })
                .limit(1000);

            if (!fetchAllContacts && user?.id) {
                query = query.eq('user_id', user.id);
            }

            const { data, error } = await query;

            if (error) {
                console.error('[useCRM] Error fetching contacts:', error);
                throw error;
            }

            return (data || []) as CRMContact[];
        },
        enabled: !!user?.id || fetchAllContacts,
        staleTime: 5 * 60 * 1000,
        gcTime: 10 * 60 * 1000,
    });

    // =========================================
    // Query: Buscar deals com contatos
    // =========================================
    const dealsQuery = useQuery({
        queryKey: [CRM_DEALS_KEY, user?.id, viewAsUserIds?.join(','), canViewAll],
        queryFn: async (): Promise<CRMDealWithContact[]> => {
            if (!user?.id) return [];

            let query = supabase
                .from('crm_deals')
                .select(`
                    *,
                    contact:crm_contacts!crm_deals_contact_id_fkey(
                        id, full_name, email, phone, company
                    )
                `)
                .order('position', { ascending: true })
                .limit(500);

            // Filtrar por usuários específicos se fornecido
            if (viewAsUserIds && viewAsUserIds.length > 0) {
                const idsString = viewAsUserIds.join(',');
                query = query.or(`user_id.in.(${idsString}),assigned_to.in.(${idsString})`);
            } else if (!canViewAll) {
                // Se não pode ver todos, filtrar por próprio usuário
                query = query.or(`user_id.eq.${user.id},assigned_to.eq.${user.id}`);
            }

            const { data, error } = await query;

            if (error) {
                console.error('[useCRM] Error fetching deals:', error);
                throw error;
            }

            const dealsData = (data || []) as CRMDealWithContact[];

            // Buscar perfis dos donos e atribuídos
            if (dealsData.length > 0) {
                const profileIds = [
                    ...new Set([
                        ...dealsData.map(d => d.user_id),
                        ...dealsData.map(d => d.assigned_to)
                    ].filter(Boolean))
                ];

                if (profileIds.length > 0) {
                    const { data: profiles } = await supabase
                        .from('profiles')
                        .select('id, full_name, email')
                        .in('id', profileIds);

                    const profileMap = new Map(
                        (profiles || []).map((p: { id: string; full_name: string | null; email: string }) => [p.id, p])
                    );

                    return dealsData.map(deal => ({
                        ...deal,
                        owner_profile: profileMap.get(deal.user_id) || null,
                        assigned_to_profile: deal.assigned_to ? profileMap.get(deal.assigned_to) || null : null,
                    }));
                }
            }

            return dealsData.map(deal => ({
                ...deal,
                owner_profile: null,
                assigned_to_profile: null,
            }));
        },
        enabled: !!user?.id,
        staleTime: 5 * 60 * 1000,
        gcTime: 10 * 60 * 1000,
    });

    // =========================================
    // Mutation: Criar contato
    // =========================================
    const createContactMutation = useMutation({
        mutationFn: async (data: Partial<CRMContact>): Promise<CRMContact> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const payload = {
                ...data,
                user_id: user.id,
                organization_id: profile?.organization_id,
            };

            const { data: result, error } = await supabase
                .from('crm_contacts')
                .insert(payload as never)
                .select()
                .single();

            if (error) throw error;
            return result as CRMContact;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_CONTACTS_KEY] });
            toast({ title: 'Contato criado com sucesso' });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao criar contato',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Criar deal
    // =========================================
    const createDealMutation = useMutation({
        mutationFn: async (data: Partial<CRMDeal>): Promise<CRMDeal> => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const payload = {
                ...data,
                user_id: user.id,
                organization_id: profile?.organization_id,
            };

            const { data: result, error } = await supabase
                .from('crm_deals')
                .insert(payload as never)
                .select()
                .single();

            if (error) throw error;
            return result as CRMDeal;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_DEALS_KEY] });
            toast({ title: 'Deal criado com sucesso' });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao criar deal',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Atualizar deal
    // =========================================
    const updateDealMutation = useMutation({
        mutationFn: async ({
            dealId,
            data,
        }: {
            dealId: string;
            data: Partial<CRMDeal>;
        }): Promise<CRMDeal> => {
            const { data: result, error } = await supabase
                .from('crm_deals')
                .update(data as never)
                .eq('id', dealId)
                .select()
                .single();

            if (error) throw error;
            return result as CRMDeal;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_DEALS_KEY] });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao atualizar deal',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Atualizar posições de deals
    // =========================================
    const updateDealsPositionsMutation = useMutation({
        mutationFn: async (updates: { id: string; position: number }[]): Promise<void> => {
            for (const update of updates) {
                const { error } = await supabase
                    .from('crm_deals')
                    .update({ position: update.position } as never)
                    .eq('id', update.id);

                if (error) throw error;
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_DEALS_KEY] });
        },
    });

    // =========================================
    // Mutation: Deletar deal
    // =========================================
    const deleteDealMutation = useMutation({
        mutationFn: async (dealId: string): Promise<void> => {
            // Verificar permissão
            if (user?.id && !isAdmin && profile?.role !== 'dono') {
                const { data: deal } = await supabase
                    .from('crm_deals')
                    .select('user_id')
                    .eq('id', dealId)
                    .single() as { data: { user_id: string } | null };

                if (deal && deal.user_id !== user.id) {
                    throw new Error('Sem permissão para deletar este deal');
                }
            }

            const { error } = await supabase
                .from('crm_deals')
                .delete()
                .eq('id', dealId);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_DEALS_KEY] });
            toast({ title: 'Deal excluído com sucesso' });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao excluir deal',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // =========================================
    // Mutation: Atualizar contato
    // =========================================
    const updateContactMutation = useMutation({
        mutationFn: async ({
            contactId,
            data,
        }: {
            contactId: string;
            data: Partial<CRMContact>;
        }): Promise<CRMContact> => {
            const { data: result, error } = await supabase
                .from('crm_contacts')
                .update(data as never)
                .eq('id', contactId)
                .select()
                .single();

            if (error) throw error;
            return result as CRMContact;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [CRM_CONTACTS_KEY] });
            queryClient.invalidateQueries({ queryKey: [CRM_DEALS_KEY] });
        },
        onError: (error: Error) => {
            toast({
                title: 'Erro ao atualizar contato',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    return {
        // Data
        contacts: contactsQuery.data || [],
        deals: dealsQuery.data || [],
        isLoading: contactsQuery.isLoading || dealsQuery.isLoading,
        isLoadingContacts: contactsQuery.isLoading,
        isLoadingDeals: dealsQuery.isLoading,

        // Mutations
        createContact: createContactMutation.mutateAsync,
        isCreatingContact: createContactMutation.isPending,

        createDeal: createDealMutation.mutateAsync,
        isCreatingDeal: createDealMutation.isPending,

        updateDeal: updateDealMutation.mutateAsync,
        isUpdatingDeal: updateDealMutation.isPending,

        updateDealsPositions: updateDealsPositionsMutation.mutateAsync,

        deleteDeal: deleteDealMutation.mutateAsync,
        isDeletingDeal: deleteDealMutation.isPending,

        updateContact: updateContactMutation.mutateAsync,
        isUpdatingContact: updateContactMutation.isPending,

        // Refetch
        refetchContacts: contactsQuery.refetch,
        refetchDeals: dealsQuery.refetch,
    };
}
